fun isDeviceRooted(): Boolean {
    val suPaths = arrayOf(
        "/system/bin/su", "/system/xbin/su",
        "/sbin/su", "/system/app/Superuser.apk"
    )
    return suPaths.any { File(it).exists() } ||
           Build.TAGS?.contains("test-keys") == true
}
